custom_css:
[selector = "address-item"]{
    padding: 1.5rem;
    border: 1px solid #BFBFBF;
    border-radius: 15px;
    box-shadow: 2px 2px 4px rgba(0, 0, 0, 0.404);
    margin-top: 2rem;
    margin-bottom: 2rem;
}

[selector = "find-button"]{
    display: flex;
    align-items: flex-end;
    justify-content: flex-start;
    height: 100%;
}
